            "Trait_Favor":{"name":"Trait_Favor","fieldName":"favor","group":"Trait","descriptions":["Favor is how much your social opponent(s) are being likeable to you. Favor can be leveraged to encourage a more favorable decision from another. This technique will modify favor."],
                "variable":"trt-favor{0}{1}","title":"Favor","subGroup":"Social Keyword","abbreviation":"","baseFormula":"","modifiers":"","formula":{"formulaString":"","workers":[]},
                "linkedGroups":[],
                "isResource":""},
            "Trait_Influence":{"name":"Trait_Influence","fieldName":"influence","group":"Trait","descriptions":["This technique will modify the severity of an influence. Influences are the the aspects of a character that connect them to the world. Influences can be leveraged to make an argument more likely to appeal to another character. "],
                "variable":"trt-influence{0}{1}","title":"Influence","subGroup":"Social Keyword","abbreviation":"","baseFormula":"","modifiers":"","formula":{"formulaString":"","workers":[]},
                "linkedGroups":[],
                "isResource":""},
            "Trait_Request":{"name":"Trait_Request","fieldName":"request","group":"Trait","descriptions":["A request check is performed when a character attempts to convince another to do something. When making a request check a character must first make a request of the target. The nature of the request will set the difficulty class (DC) of the request check. Most request checks will require that you roll some dice and add relevant modifiers such as favor. ","You will always add any relevant influence modifiers to the check. An influence may support or oppose a request. If the influence is supportive of a request, you will add its severity modifier to the request check. An opposing influence will likewise subtract its severity modifier from the request check. Only one influence can support or oppose a request. If multiple influences apply to support or oppose a request, only the highest severity influence will count each for support and oppose.","Usually some kind of influence is required over the target in order to convince them to do anything more complicated than a simple request. Most of the DCs for more complicated requests require the bonuses granted from a supporting influence.","A request check is always performed with a request to be made of the target. This usually comes in the form of a task. The nature of the task will determine the DC of the request check."],
                "variable":"trt-request{0}{1}","title":"Request","subGroup":"Social Keyword","abbreviation":"","baseFormula":"","modifiers":"","formula":{"formulaString":"","workers":[]},
                "linkedGroups":[],
                "isResource":""},
